import { useRouter, usePathname, useSearchParams } from 'next/navigation';

function ServicesContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const pathname = usePathname();
  const initialCategory = searchParams.get('category') || 'cx-sales';
  const [activeCategoryId, setActiveCategoryId] = useState<string>(initialCategory);
  const [searchQuery, setSearchQuery] = useState('');
  const [isNavHovered, setIsNavHovered] = useState(false);

  // Sync state if query param changes (e.g. back button)
  useEffect(() => {
    const cat = searchParams.get('category');
    if (cat && cat !== activeCategoryId) {
      setActiveCategoryId(cat);
    }
  }, [searchParams]);
  
  const handleCategoryClick = (categoryId: string) => {
    setActiveCategoryId(categoryId);
    // Update URL without a full page refresh
    const params = new URLSearchParams(searchParams.toString());
    params.set('category', categoryId);
    router.push(`${pathname}?${params.toString()}`, { scroll: false });
    
    // Optional: Center the clicked item in the scroll view
    const element = document.getElementById(`nav-item-${categoryId}`);
    element?.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
  };
  const filteredServices = useMemo(() => {
    let results = SERVICES;
    if (activeCategoryId !== 'all') {
      results = results.filter(s => s.category === activeCategoryId);
    }
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      results = results.filter(s => 
        s.name.toLowerCase().includes(query) || 
        s.description.toLowerCase().includes(query)
      );
    }
    return results;
  }, [activeCategoryId, searchQuery]);

  const activeCategory = useMemo(() => 
    CATEGORIES.find(c => c.id === activeCategoryId)
  , [activeCategoryId]);

  return (
    <div className="relative w-full text-gray-900 selection:bg-[#F97316]/20">
      {/* Cinematic Mesh Background */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        <div className="absolute inset-0 bg-gemini-light" />
        
        {/* Animated Mesh blobs - adjusted for light theme */}
        <motion.div 
          animate={{
            scale: [1, 1.2, 1],
            x: [0, 100, 0],
            y: [0, -50, 0],
          }}
          transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
          className="absolute -top-[20%] -left-[10%] w-[80%] h-[80%] bg-[#F97316]/10 blur-[120px] rounded-full pointer-events-none opacity-50"
        />
        <motion.div 
          animate={{
            scale: [1, 1.3, 1],
            x: [0, -120, 0],
            y: [0, 80, 0],
          }}
          transition={{ duration: 25, repeat: Infinity, ease: "linear" }}
          className="absolute -bottom-[10%] -right-[10%] w-[70%] h-[70%] bg-blue-500/5 blur-[120px] rounded-full pointer-events-none opacity-40"
        />

        {/* Waves overlay - subtle for light theme */}
        <div className="absolute inset-0 opacity-[0.03] pointer-events-none text-black/5">
          <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
            <defs>
              <filter id="grain">
                <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" />
                <feColorMatrix type="saturate" values="0" />
              </filter>
            </defs>
            <rect width="100%" height="100%" filter="url(#grain)" />
          </svg>
        </div>
        
        {/* Soft Mesh Overlay Gradient */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-white/20 to-white/60" />
      </div>

      {/* Main Content Stage */}
      <div className="relative z-10 flex flex-col w-full">
        
        {/* Feature Stage (Solution Clusters) */}
        <main className="pt-12 pb-32 overflow-hidden px-6">
          <div className="max-w-7xl mx-auto text-center mb-8">
            {/* Inline Navigation Menu - Clearly Visible & Scrollable */}
            <div className="flex justify-center mb-16 px-4">
              <div className="relative max-w-full lg:max-w-7xl">
                {/* Horizontal scroll fade indicators */}
                <div className="absolute left-0 top-0 bottom-0 w-8 bg-gradient-to-r from-gemini-light to-transparent z-20 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity" />
                <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-gemini-light to-transparent z-20 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity" />
                
                <motion.nav 
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  className="bg-white/60 backdrop-blur-2xl border border-black/5 p-1.5 rounded-full shadow-xl flex items-center gap-1 overflow-x-auto no-scrollbar scroll-smooth"
                >
                  {CATEGORIES.map((cat) => (
                    <button
                      key={cat.id}
                      onClick={() => handleCategoryClick(cat.id)}
                      id={`nav-item-${cat.id}`}
                      className={`relative px-8 py-4 rounded-full text-[10px] lg:text-xs font-black transition-all duration-500 whitespace-nowrap uppercase tracking-[0.2em] ${
                        activeCategoryId === cat.id ? 'text-gray-900' : 'text-gray-400 hover:text-gray-900 hover:bg-black/5'
                      }`}
                    >
                      {activeCategoryId === cat.id && (
                        <motion.div
                          layoutId="active-nav-inline"
                          className="absolute inset-0 bg-[#F97316]/10 border border-[#F97316]/20 rounded-full"
                          transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                        />
                      )}
                      <span className="relative z-10">{cat.name}</span>
                    </button>
                  ))}
                </motion.nav>
              </div>
            </div>
          </div>

          <div className="w-full max-w-[1600px] mx-auto py-10 relative">
            <AnimatePresence mode="wait">
              <motion.div 
                key={activeCategoryId}
                className="flex flex-col lg:flex-row items-center justify-center gap-10"
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -30 }}
                transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
              >
                {/* Enterprise Cluster Card */}
                <EnterpriseCard 
                  category={activeCategory!} 
                  services={filteredServices}
                />
              </motion.div>
            </AnimatePresence>
          </div>
        </main>

      </div>

      <style jsx global>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        .perspective-1000 { perspective: 1000px; }
        
        @keyframes scan {
          0% { transform: translateY(-100%); }
          100% { transform: translateY(100%); }
        }
        .scanline {
          position: absolute;
          top: 0; left: 0; width: 100%; height: 2px;
          background: linear-gradient(to right, transparent, rgba(0,0,0,0.05), transparent);
          animation: scan 4s linear infinite;
          pointer-events: none;
        }
      `}</style>
    </div>
  );
}

